export interface DBEntry {
  id: string;
  [key: string]: any;
}

export interface Collection {
  name: string;
  entries: DBEntry[];
}

export interface ProjectPermissions {
  allowPublicRead: boolean;
  allowPublicWrite: boolean; // Dangerous, but sometimes needed
  allowedOrigins: string[]; // CORS support
}

export interface Project {
  id: string;
  ownerId: string; // Link to User
  name: string;
  description?: string;
  apiKey: string; // Public key for frontend
  secretKey?: string; // Private key for server-side admin
  permissions: ProjectPermissions;
  collections: Collection[];
  createdAt: string;
  updatedAt: string;
}

export interface User {
  uid: string;
  email: string;
  displayName: string;
  photoURL?: string;
}

export type LogType = 'info' | 'success' | 'error' | 'warning';

export interface LogEntry {
  timestamp: string;
  type: LogType;
  message: string;
}

export enum ViewState {
  LANDING = 'LANDING',
  DASHBOARD = 'DASHBOARD',
  DOCS = 'DOCS',
  PLAYGROUND = 'PLAYGROUND',
  AUTH = 'AUTH'
}

import { initializeApp } from 'firebase/app';
import { getAuth } from 'firebase/auth';
import { getFirestore } from 'firebase/firestore';

// ------------------------------------------------------------------
// CONFIGURATION REQUIRED:
// Paste your Firebase Config object below.
// You can get this from the Firebase Console -> Project Settings.
// ------------------------------------------------------------------
const firebaseConfig = {
  apiKey: "REPLACE_WITH_YOUR_FIREBASE_API_KEY",
  authDomain: "REPLACE_WITH_YOUR_PROJECT_ID.firebaseapp.com",
  projectId: "REPLACE_WITH_YOUR_PROJECT_ID",
  storageBucket: "REPLACE_WITH_YOUR_PROJECT_ID.appspot.com",
  messagingSenderId: "123456789",
  appId: "1:123456789:web:abcdef123456"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
export const db = getFirestore(app);

import { 
  collection, 
  addDoc, 
  getDocs, 
  query, 
  where, 
  doc, 
  deleteDoc, 
  updateDoc, 
  getDoc,
  serverTimestamp
} from 'firebase/firestore';
import { auth, db } from '../lib/firebase';
import { Project, DBEntry, Collection } from '../types';

// Helper to convert Firestore snapshots to our App types
const mapDocToProject = async (docSnap: any): Promise<Project> => {
  const data = docSnap.data();
  // We need to fetch collections manually since they are subcollections
  // Note: listing subcollections is not possible directly in client SDK without knowing names
  // For this architecture, we will store a metadata array of collection names on the parent project doc
  // OR we just query the known collections. 

  // Strategy: For the dashboard to be fast, we will store a 'collectionNames' array on the Project document.
  // When we fetch a project, we iterate those names to fetch the data.

  const colNames: string[] = data.collectionList || [];
  const collections: Collection[] = [];

  for (const name of colNames) {
    const colRef = collection(db, `projects/${docSnap.id}/collections/${name}/docs`);
    const snapshot = await getDocs(colRef);
    const entries = snapshot.docs.map(d => ({ id: d.id, ...d.data() }));
    collections.push({ name, entries });
  }

  return {
    id: docSnap.id,
    ownerId: data.ownerId,
    name: data.name,
    apiKey: data.apiKey,
    secretKey: data.secretKey,
    permissions: data.permissions,
    collections,
    createdAt: data.createdAt?.toDate?.()?.toISOString() || new Date().toISOString(),
    updatedAt: data.updatedAt?.toDate?.()?.toISOString() || new Date().toISOString(),
  };
};

export const FirebaseService = {
  // --- Management API ---

  createProject: async (name: string): Promise<Project> => {
    const user = auth.currentUser;
    if (!user) throw new Error("Must be logged in");

    const newProject = {
      ownerId: user.uid,
      name,
      apiKey: `pk_live_${Math.random().toString(36).substr(2, 16)}`,
      secretKey: `sk_live_${Math.random().toString(36).substr(2, 16)}`,
      permissions: {
        allowPublicRead: true,
        allowPublicWrite: false,
        allowedOrigins: ['perchance.org']
      },
      collectionList: [], // Metadata to track subcollections
      createdAt: serverTimestamp(),
      updatedAt: serverTimestamp()
    };

    const docRef = await addDoc(collection(db, 'projects'), newProject);

    // Return formatted project
    return {
      id: docRef.id,
      ...newProject,
      collections: [],
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    } as Project;
  },

  getAllProjects: async (): Promise<Project[]> => {
    const user = auth.currentUser;
    if (!user) return [];

    const q = query(collection(db, 'projects'), where('ownerId', '==', user.uid));
    const querySnapshot = await getDocs(q);

    const projects = await Promise.all(querySnapshot.docs.map(mapDocToProject));
    return projects;
  },

  // --- Runtime API (Used by Playground & eventually the Vercel API) ---

  runtimeAdd: async (apiKey: string, collectionName: string, data: any): Promise<any> => {
    // 1. Find Project by API Key (This requires a global query, strictly needs an index in Firestore)
    // Note: In a real high-scale app, we'd use the Project ID directly, but per user request we look up by key.
    const q = query(collection(db, 'projects'), where('apiKey', '==', apiKey));
    const querySnapshot = await getDocs(q);

    if (querySnapshot.empty) throw new Error("Invalid API Key");
    const projectDoc = querySnapshot.docs[0];
    const projectId = projectDoc.id;

    // 2. Ensure collection name is in the list
    const projectData = projectDoc.data();
    const currentList: string[] = projectData.collectionList || [];

    if (!currentList.includes(collectionName)) {
      await updateDoc(doc(db, 'projects', projectId), {
        collectionList: [...currentList, collectionName],
        updatedAt: serverTimestamp()
      });
    }

    // 3. Add Data
    const colRef = collection(db, `projects/${projectId}/collections/${collectionName}/docs`);
    const docRef = await addDoc(colRef, {
      ...data,
      _created: serverTimestamp()
    });

    return { id: docRef.id, ...data };
  },

  runtimeGet: async (apiKey: string, collectionName: string): Promise<DBEntry[]> => {
    const q = query(collection(db, 'projects'), where('apiKey', '==', apiKey));
    const querySnapshot = await getDocs(q);
    if (querySnapshot.empty) throw new Error("Invalid API Key");

    const projectId = querySnapshot.docs[0].id;
    const colRef = collection(db, `projects/${projectId}/collections/${collectionName}/docs`);
    const snapshot = await getDocs(colRef);

    return snapshot.docs.map(d => ({ id: d.id, ...d.data() }));
  },

  runtimeUpdate: async (apiKey: string, collectionName: string, docId: string, data: any): Promise<void> => {
    const q = query(collection(db, 'projects'), where('apiKey', '==', apiKey));
    const querySnapshot = await getDocs(q);
    if (querySnapshot.empty) throw new Error("Invalid API Key");

    const projectId = querySnapshot.docs[0].id;
    const docRef = doc(db, `projects/${projectId}/collections/${collectionName}/docs`, docId);

    await updateDoc(docRef, data);
  },

  runtimeDelete: async (apiKey: string, collectionName: string, docId: string): Promise<void> => {
    const q = query(collection(db, 'projects'), where('apiKey', '==', apiKey));
    const querySnapshot = await getDocs(q);
    if (querySnapshot.empty) throw new Error("Invalid API Key");

    const projectId = querySnapshot.docs[0].id;
    const docRef = doc(db, `projects/${projectId}/collections/${collectionName}/docs`, docId);

    await deleteDoc(docRef);
  }
};

import React, { useState } from 'react';
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  updateProfile 
} from 'firebase/auth';
import { auth } from '../lib/firebase';
import { Button, Input, Card } from '../components/ui';
import { Database, LogIn, UserPlus, AlertCircle } from 'lucide-react';
import { ViewState } from '../types';

interface AuthProps {
  onSuccess: () => void;
}

export const Auth: React.FC<AuthProps> = ({ onSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      if (isLogin) {
        await signInWithEmailAndPassword(auth, email, password);
      } else {
        const cred = await createUserWithEmailAndPassword(auth, email, password);
        await updateProfile(cred.user, { displayName: name });
      }
      onSuccess();
    } catch (err: any) {
      console.error(err);
      let msg = "Authentication failed.";
      if (err.code === 'auth/invalid-credential') msg = "Invalid email or password.";
      if (err.code === 'auth/email-already-in-use') msg = "Email already in use.";
      if (err.code === 'auth/weak-password') msg = "Password should be at least 6 characters.";
      setError(msg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-[calc(100vh-64px)] flex items-center justify-center p-4">
      <Card className="w-full max-w-md border-brand-500/30 bg-slate-900/50">
        <div className="text-center mb-8">
          <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-brand-500 to-brand-700 flex items-center justify-center mx-auto mb-4 shadow-lg shadow-brand-500/20">
            <Database className="w-6 h-6 text-white" />
          </div>
          <h2 className="text-2xl font-bold text-white">
            {isLogin ? 'Welcome Back' : 'Create Account'}
          </h2>
          <p className="text-slate-400 text-sm mt-2">
            {isLogin ? 'Enter your credentials to access your dashboard.' : 'Start building your cloud database today.'}
          </p>
        </div>

        {error && (
          <div className="mb-6 bg-red-500/10 border border-red-500/20 rounded-lg p-3 flex items-center gap-3 text-red-400 text-sm">
            <AlertCircle className="w-4 h-4 shrink-0" />
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-4">
          {!isLogin && (
            <Input 
              label="Display Name" 
              placeholder="Creator Name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
            />
          )}
          <Input 
            label="Email" 
            type="email" 
            placeholder="you@example.com"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
          />
          <Input 
            label="Password" 
            type="password" 
            placeholder="••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
          />

          <Button 
            type="submit" 
            className="w-full mt-2" 
            isLoading={loading}
            icon={isLogin ? LogIn : UserPlus}
          >
            {isLogin ? 'Sign In' : 'Create Account'}
          </Button>
        </form>

        <div className="mt-6 text-center">
          <button 
            onClick={() => setIsLogin(!isLogin)}
            className="text-sm text-slate-400 hover:text-brand-400 transition-colors"
          >
            {isLogin ? "Don't have an account? Sign up" : "Already have an account? Sign in"}
          </button>
        </div>
      </Card>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Plus, Database, Key, Trash2, RefreshCw, Layers, Table as TableIcon, FileJson, Search, Pencil, Save, X, ChevronLeft, ChevronRight } from 'lucide-react';
import { FirebaseService } from '../services/firebaseService';
import { Project, Collection, DBEntry } from '../types';
import { Button, Card, Input, Badge, Modal } from '../components/ui';

// --- Sub-components for Data Visualization ---

const ITEMS_PER_PAGE = 10;

const CollectionTable = ({ 
  entries, 
  onEdit, 
  onDelete 
}: { 
  entries: DBEntry[], 
  onEdit: (entry: DBEntry) => void,
  onDelete: (entry: DBEntry) => void 
}) => {
  const [currentPage, setCurrentPage] = useState(1);

  // Reset to first page when entries (collection) changes
  useEffect(() => {
    setCurrentPage(1);
  }, [entries]);

  if (entries.length === 0) {
    return <div className="p-8 text-center text-slate-500 italic text-sm">No records in this collection. Add data to see it here.</div>;
  }

  // Pagination Logic
  const totalPages = Math.ceil(entries.length / ITEMS_PER_PAGE);
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
  const paginatedEntries = entries.slice(startIndex, startIndex + ITEMS_PER_PAGE);

  // Dynamically determine all unique keys across all entries (using full set for headers consistency)
  const allKeys = Array.from(new Set(entries.flatMap(entry => Object.keys(entry))));

  // Sort headers: 'id' first, then '_created', then alphabetical for the rest
  const headers = [
    'id',
    ...allKeys.filter(k => k !== 'id' && k !== '_created').sort(),
    ...(allKeys.includes('_created') ? ['_created'] : [])
  ];

  return (
    <div className="flex flex-col h-full">
      <div className="overflow-x-auto custom-scrollbar pb-2 flex-1">
        <table className="min-w-full divide-y divide-slate-800/50 text-left border-collapse">
          <thead className="bg-slate-900 sticky top-0 z-10">
            <tr>
              {headers.map(header => (
                <th key={header} className="px-4 py-3 text-xs font-semibold text-slate-400 uppercase tracking-wider whitespace-nowrap border-b border-slate-700 select-none">
                  {header}
                </th>
              ))}
              <th className="px-4 py-3 text-xs font-semibold text-slate-400 uppercase tracking-wider whitespace-nowrap border-b border-slate-700 text-right sticky right-0 bg-slate-900 shadow-[-10px_0_10px_-5px_rgba(0,0,0,0.3)]">
                Actions
              </th>
            </tr>
          </thead>
          <tbody className="bg-slate-900/20 divide-y divide-slate-800/50">
            {paginatedEntries.map((entry) => (
              <tr key={entry.id} className="hover:bg-slate-800/50 transition-colors group">
                {headers.map(header => {
                  const value = entry[header];
                  let displayValue: React.ReactNode = value;
                  let isComplex = false;
                  let isEmpty = value === null || value === undefined;

                  if (isEmpty) {
                    displayValue = <span className="text-slate-700">-</span>;
                  } else if (typeof value === 'object') {
                    displayValue = JSON.stringify(value);
                    isComplex = true;
                  } else if (typeof value === 'boolean') {
                    displayValue = value ? (
                      <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-medium bg-emerald-500/10 text-emerald-400 border border-emerald-500/20">TRUE</span>
                    ) : (
                      <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-medium bg-red-500/10 text-red-400 border border-red-500/20">FALSE</span>
                    );
                  }

                  return (
                    <td key={`${entry.id}-${header}`} className="px-4 py-2 text-sm text-slate-300 whitespace-nowrap border-r border-slate-800/30 last:border-r-0 max-w-[250px]">
                      <div 
                        className={`truncate ${isComplex ? 'font-mono text-xs text-slate-500' : ''}`} 
                        title={typeof value === 'object' ? JSON.stringify(value, null, 2) : String(value)}
                      >
                        {displayValue}
                      </div>
                    </td>
                  );
                })}
                {/* Actions Column */}
                <td className="px-4 py-2 text-right sticky right-0 bg-slate-900/90 group-hover:bg-slate-800 backdrop-blur-sm border-l border-slate-800/50 shadow-[-10px_0_10px_-5px_rgba(0,0,0,0.3)]">
                   <div className="flex justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => onEdit(entry)} className="p-1 text-slate-400 hover:text-brand-400 hover:bg-brand-500/10 rounded transition-colors" title="Edit JSON">
                        <Pencil className="w-3.5 h-3.5" />
                      </button>
                      <button onClick={() => onDelete(entry)} className="p-1 text-slate-400 hover:text-red-400 hover:bg-red-500/10 rounded transition-colors" title="Delete">
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                   </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Pagination Controls */}
      {totalPages > 1 && (
        <div className="flex items-center justify-between px-4 py-3 bg-slate-900/50 border-t border-slate-700/50">
          <div className="text-xs text-slate-400">
            Showing <span className="font-medium text-slate-200">{startIndex + 1}</span> to <span className="font-medium text-slate-200">{Math.min(startIndex + ITEMS_PER_PAGE, entries.length)}</span> of <span className="font-medium text-slate-200">{entries.length}</span> results
          </div>
          <div className="flex space-x-2">
            <Button 
              size="sm" 
              variant="outline" 
              onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
              disabled={currentPage === 1}
              className="px-2"
            >
              <ChevronLeft className="w-4 h-4" />
            </Button>
            <div className="flex items-center px-2 text-xs font-mono text-slate-400 bg-slate-800 rounded">
              Page {currentPage} / {totalPages}
            </div>
            <Button 
              size="sm" 
              variant="outline" 
              onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
              disabled={currentPage === totalPages}
              className="px-2"
            >
              <ChevronRight className="w-4 h-4" />
            </Button>
          </div>
        </div>
      )}
    </div>
  );
};

const CollectionViewer = ({ 
  collection, 
  projectApiKey,
  onRefresh 
}: { 
  collection: Collection, 
  projectApiKey: string,
  onRefresh: () => void 
}) => {
  const [viewMode, setViewMode] = useState<'table' | 'json'>('table');
  const [editingEntry, setEditingEntry] = useState<DBEntry | null>(null);
  const [editJson, setEditJson] = useState('');
  const [deletingEntry, setDeletingEntry] = useState<DBEntry | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // --- Handlers ---

  const handleEditClick = (entry: DBEntry) => {
    setEditingEntry(entry);
    setEditJson(JSON.stringify(entry, null, 2));
  };

  const handleSaveEdit = async () => {
    if (!editingEntry) return;
    setIsProcessing(true);
    try {
      const parsedData = JSON.parse(editJson);
      // Remove ID from data to prevent changing it
      const { id, ...dataToUpdate } = parsedData; 

      await FirebaseService.runtimeUpdate(projectApiKey, collection.name, editingEntry.id, dataToUpdate);
      setEditingEntry(null);
      onRefresh();
    } catch (e) {
      alert("Invalid JSON or Error Saving");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDeleteClick = (entry: DBEntry) => {
    setDeletingEntry(entry);
  };

  const confirmDelete = async () => {
    if (!deletingEntry) return;
    setIsProcessing(true);
    await FirebaseService.runtimeDelete(projectApiKey, collection.name, deletingEntry.id);
    setDeletingEntry(null);
    setIsProcessing(false);
    onRefresh();
  };

  return (
    <>
      <div className="border border-slate-700/50 rounded-lg overflow-hidden mb-6 bg-slate-900/20 flex flex-col">
        {/* Viewer Header */}
        <div className="bg-slate-900/80 px-4 py-3 border-b border-slate-700/50 flex flex-col sm:flex-row justify-between items-start sm:items-center backdrop-blur-sm gap-4 sm:gap-0">
           <div className="flex items-center space-x-3">
               <div className="font-mono text-sm text-brand-400 font-bold px-2.5 py-1 bg-brand-500/10 rounded border border-brand-500/20 flex items-center">
                 <Layers className="w-3.5 h-3.5 mr-2 opacity-70" />
                 {collection.name}
               </div>
               <span className="text-xs text-slate-500 border-l border-slate-700 pl-3">
                 {collection.entries.length} {collection.entries.length === 1 ? 'Entry' : 'Entries'}
               </span>
           </div>

           {/* Toggle Controls */}
           <div className="flex bg-slate-800 rounded-lg p-1 space-x-1">
              <button 
                onClick={() => setViewMode('table')}
                className={`flex items-center px-3 py-1.5 rounded-md text-xs font-medium transition-all ${
                  viewMode === 'table' 
                    ? 'bg-slate-600 text-white shadow-sm' 
                    : 'text-slate-400 hover:text-slate-300 hover:bg-slate-700/50'
                }`}
              >
                <TableIcon className="w-3.5 h-3.5 mr-1.5" />
                Table
              </button>
              <button 
                onClick={() => setViewMode('json')}
                className={`flex items-center px-3 py-1.5 rounded-md text-xs font-medium transition-all ${
                  viewMode === 'json' 
                    ? 'bg-slate-600 text-white shadow-sm' 
                    : 'text-slate-400 hover:text-slate-300 hover:bg-slate-700/50'
                }`}
              >
                <FileJson className="w-3.5 h-3.5 mr-1.5" />
                JSON
              </button>
           </div>
        </div>

        {/* Content Area */}
        {viewMode === 'table' ? (
          <CollectionTable 
            entries={collection.entries} 
            onEdit={handleEditClick}
            onDelete={handleDeleteClick}
          />
        ) : (
          <div className="bg-slate-950 px-4 py-4 overflow-x-auto max-h-[500px] custom-scrollbar">
             <pre className="text-xs text-slate-400 font-mono leading-relaxed">
               {JSON.stringify(collection.entries, null, 2)}
             </pre>
          </div>
        )}
      </div>

      {/* Edit Modal */}
      <Modal 
        isOpen={!!editingEntry} 
        onClose={() => setEditingEntry(null)} 
        title="Edit Document"
      >
        <div className="space-y-4">
           <div className="text-xs text-slate-500 font-mono mb-2">ID: {editingEntry?.id}</div>
           <textarea
             className="w-full h-64 bg-slate-950 border border-slate-700 rounded-lg p-3 font-mono text-sm text-slate-300 focus:ring-1 focus:ring-brand-500 focus:outline-none custom-scrollbar"
             value={editJson}
             onChange={(e) => setEditJson(e.target.value)}
           />
           <div className="flex justify-end gap-2">
             <Button variant="secondary" onClick={() => setEditingEntry(null)}>Cancel</Button>
             <Button icon={Save} onClick={handleSaveEdit} isLoading={isProcessing}>Save Changes</Button>
           </div>
        </div>
      </Modal>

      {/* Delete Confirmation Modal */}
      <Modal 
        isOpen={!!deletingEntry} 
        onClose={() => setDeletingEntry(null)} 
        title="Delete Document"
      >
        <div className="space-y-4">
