// --- Tab: JS Runtime ---

const INITIAL_CODE = `// 1. Initialize DB 
// (Replace with a key from your Dashboard)
const apiKey = "pk_live_REPLACE_ME";

// 2. Define some data
const hero = {
  name: "Hero_" + Math.floor(Math.random() * 1000),
  hp: 100,
  gold: 50
};

// 3. Save to 'players' collection
log("Saving hero...", "info");
const result = await db.save(apiKey, "players", hero);
log("Saved! ID: " + result.id, "success");

// 4. Fetch all players
log("Fetching leaderboard...", "info");
const players = await db.fetch(apiKey, "players");
log("Found " + players.length + " players.", "info");
console.log(players); // Check console for full object
`;

const RuntimeTab: React.FC = () => {
  const [code, setCode] = useState(INITIAL_CODE);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [isRunning, setIsRunning] = useState(false);
  const logsEndRef = useRef<HTMLDivElement>(null);

  const addLog = (message: string, type: 'info' | 'success' | 'error' | 'warning' = 'info') => {
    setLogs(prev => [...prev, {
      timestamp: new Date().toLocaleTimeString(),
      type,
      message
    }]);
  };

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  const runCode = async () => {
    setIsRunning(true);
    setLogs([]);
    addLog("Starting execution...", "info");

    try {
      const executionContext = async () => {
        const db = {
          save: (key: string, col: string, data: any) => FirebaseService.runtimeAdd(key, col, data),
          fetch: (key: string, col: string) => FirebaseService.runtimeGet(key, col)
        };
        const log = (msg: string, type: any) => addLog(msg, type);

        // Basic safety wrapper
        const userFunction = new Function('db', 'log', 'FirebaseService', `
          return (async () => {
            try {
              ${code}
            } catch (err) {
              log(err.message, "error");
              console.error(err);
            }
          })();
        `);

        await userFunction(db, log, FirebaseService);
      };

      await executionContext();

    } catch (error: any) {
      addLog(`Runtime Error: ${error.message}`, 'error');
    } finally {
      setIsRunning(false);
      addLog("Execution finished.", "warning");
    }
  };

  return (
    <div className="h-full flex flex-col lg:flex-row bg-slate-950 overflow-hidden">
      <div className="flex-1 flex flex-col border-r border-slate-800">
        <div className="h-12 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-4">
          <div className="flex items-center text-slate-400 text-sm">
            <Database className="w-4 h-4 mr-2" />
            <span>script.js</span>
          </div>
          <div className="flex space-x-2">
            <Button size="sm" variant="secondary" onClick={() => setCode(INITIAL_CODE)} icon={RotateCcw} title="Reset Code">
              Reset
            </Button>
            <Button size="sm" onClick={runCode} disabled={isRunning} icon={Play}>
              {isRunning ? 'Running...' : 'Run Code'}
            </Button>
          </div>
        </div>
        <div className="flex-1 relative">
          <textarea
            className="absolute inset-0 w-full h-full bg-[#0f172a] text-slate-300 font-mono text-sm p-4 resize-none focus:outline-none leading-relaxed"
            value={code}
            onChange={(e) => setCode(e.target.value)}
            spellCheck="false"
          />
        </div>
      </div>

      <div className="w-full lg:w-[400px] flex flex-col bg-[#0b1120]">
        <div className="h-12 bg-slate-900 border-b border-slate-800 flex items-center px-4">
          <span className="text-slate-400 text-sm font-medium">Console Output</span>
        </div>
        <div className="flex-1 p-4 overflow-y-auto font-mono text-xs space-y-2">
          {logs.length === 0 && (
            <div className="text-slate-600 italic">Ready to execute...</div>
          )}
          {logs.map((log, i) => (
            <div key={i} className="flex gap-2 animate-in fade-in duration-300">
              <span className="text-slate-600 shrink-0">[{log.timestamp}]</span>
              <span className={`${
                log.type === 'error' ? 'text-red-400' :
                log.type === 'success' ? 'text-emerald-400' :
                log.type === 'warning' ? 'text-amber-400' :
                'text-slate-300'
              }`}>
                {log.type === 'error' && '❌ '}
                {log.type === 'success' && '✓ '}
                {log.message}
              </span>
            </div>
          ))}
          <div ref={logsEndRef} />
        </div>
      </div>
    </div>
  );
};

// --- Tab: Security Rules ---

const INITIAL_RULES = `{
  "users": {
    ".read": "true",
    ".write": "auth.uid == resource.id"
  },
  "scores": {
    ".read": "true",
    ".write": "auth.uid != null && request.data.score < 1000"
  },
  "secrets": {
    ".read": "auth.uid == 'admin'",
    ".write": "false"
  }
}`;

const RulesTab: React.FC = () => {
  const [rules, setRules] = useState(INITIAL_RULES);
  const [testPath, setTestPath] = useState('scores/score_123');
  const [testAuth, setTestAuth] = useState('{"uid": "user_abc"}');
  const [testResource, setTestResource] = useState('{"id": "score_123", "score": 500}');
  const [testRequestData, setTestRequestData] = useState('{"score": 800}');
  const [testAction, setTestAction] = useState<'read' | 'write'>('write');
  const [result, setResult] = useState<{ allowed: boolean; reason: string } | null>(null);

  const simulateRequest = () => {
    try {
      const parsedRules = JSON.parse(rules);
      const collection = testPath.split('/')[0];

      // Basic context building
      const ctx = {
        auth: JSON.parse(testAuth),
        resource: JSON.parse(testResource), // Existing data
        request: {
           data: JSON.parse(testRequestData) // Incoming data
        }
      };

      if (!parsedRules[collection]) {
        setResult({ allowed: false, reason: "Collection not defined in rules." });
        return;
      }

      const ruleKey = testAction === 'write' ? '.write' : '.read';
      const ruleString = parsedRules[collection][ruleKey];

      if (!ruleString) {
        setResult({ allowed: false, reason: "Default Deny: No rule found." });
        return;
      }

      // Safe-ish evaluation for simulator
      const evaluator = new Function('auth', 'resource', 'request', `return ${ruleString};`);
      const isAllowed = evaluator(ctx.auth, ctx.resource, ctx.request);

      setResult({
        allowed: !!isAllowed,
        reason: isAllowed ? "Rule evaluated to true." : "Rule evaluated to false."
      });

    } catch (e: any) {
      setResult({ allowed: false, reason: `Syntax Error: ${e.message}` });
    }
  };

  return (
    <div className="h-full flex flex-col lg:flex-row bg-slate-950 overflow-hidden">
      {/* Rules Editor */}
      <div className="flex-1 flex flex-col border-r border-slate-800">
         <div className="h-12 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-4">
            <div className="flex items-center text-slate-400 text-sm">
              <Shield className="w-4 h-4 mr-2" />
              <span>security_rules.json</span>
            </div>
            <div className="text-xs text-slate-500 hidden sm:block">
              Define who can read/write to collections
            </div>
         </div>
         <div className="flex-1 relative">
            <textarea
              className="absolute inset-0 w-full h-full bg-[#0f172a] text-emerald-300 font-mono text-sm p-4 resize-none focus:outline-none leading-relaxed"
              value={rules}
              onChange={(e) => setRules(e.target.value)}
              spellCheck="false"
            />
         </div>
      </div>

      {/* Test Simulator */}
      <div className="w-full lg:w-[450px] flex flex-col bg-[#0b1120] border-l border-slate-800">
         <div className="h-12 bg-slate-900 border-b border-slate-800 flex items-center px-4">
           <span className="text-slate-400 text-sm font-medium">Request Simulator</span>
         </div>

         <div className="flex-1 overflow-y-auto p-4 space-y-6">

            {/* Action & Path */}
            <div className="grid grid-cols-3 gap-2">
              <div className="col-span-1">
                 <label className="text-[10px] text-slate-500 uppercase font-bold">Action</label>
                 <select 
                   className="w-full bg-slate-800 border border-slate-700 rounded p-2 text-sm text-white mt-1"
                   value={testAction}
                   onChange={(e) => setTestAction(e.target.value as any)}
                 >
                   <option value="read">Read (Get)</option>
                   <option value="write">Write (Add/Upd)</option>
                 </select>
              </div>
              <div className="col-span-2">
                 <label className="text-[10px] text-slate-500 uppercase font-bold">Path</label>
                 <input 
                   className="w-full bg-slate-800 border border-slate-700 rounded p-2 text-sm text-white mt-1 font-mono"
                   value={testPath}
                   onChange={(e) => setTestPath(e.target.value)}
                   placeholder="collection/doc_id"
                 />
              </div>
            </div>

            {/* Simulated Auth */}
            <div>
              <div className="flex justify-between">
                <label className="text-[10px] text-slate-500 uppercase font-bold">Auth Object (auth)</label>
                <button className="text-[10px] text-brand-400 hover:text-brand-300" onClick={() => setTestAuth('null')}>Set Null</button>
              </div>
              <textarea 
                className="w-full h-20 bg-slate-800 border border-slate-700 rounded p-2 text-xs text-slate-300 mt-1 font-mono"
                value={testAuth}
                onChange={(e) => setTestAuth(e.target.value)}
              />
            </div>

            {/* Existing Data */}
            <div>
              <label className="text-[10px] text-slate-500 uppercase font-bold">Resource (Existing Data)</label>
              <textarea 
                className="w-full h-20 bg-slate-800 border border-slate-700 rounded p-2 text-xs text-slate-300 mt-1 font-mono"
                value={testResource}
                onChange={(e) => setTestResource(e.target.value)}
              />
            </div>

            {/* Incoming Data */}
            <div className={testAction === 'read' ? 'opacity-50 pointer-events-none' : ''}>
              <label className="text-[10px] text-slate-500 uppercase font-bold">Request Data (New Data)</label>
              <textarea 
                className="w-full h-20 bg-slate-800 border border-slate-700 rounded p-2 text-xs text-slate-300 mt-1 font-mono"
                value={testRequestData}
                onChange={(e) => setTestRequestData(e.target.value)}
              />
            </div>

            <Button className="w-full" onClick={simulateRequest} icon={Play}>Run Simulation</Button>

            {/* Result */}
            {result && (
              <div className={`p-4 rounded-lg border ${result.allowed ? 'bg-emerald-900/20 border-emerald-500/50' : 'bg-red-900/20 border-red-500/50'} animate-in slide-in-from-bottom-2`}>
                 <div className="flex items-center gap-2 mb-1">
                   {result.allowed ? <CheckCircle className="w-5 h-5 text-emerald-400" /> : <XCircle className="w-5 h-5 text-red-400" />}
                   <span className={`font-bold ${result.allowed ? 'text-emerald-400' : 'text-red-400'}`}>
                     {result.allowed ? 'ALLOWED' : 'DENIED'}
                   </span>
                 </div>
                 <p className="text-xs text-slate-400 ml-7">{result.reason}</p>
              </div>
            )}

         </div>
      </div>
    </div>
  );
};

