import React, { useState, useEffect } from 'react';
import { Database, Home as HomeIcon, LayoutDashboard, Book, Code, Menu, X, LogOut, User } from 'lucide-react';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { auth } from './lib/firebase';
import { ViewState } from './types';
import { Home } from './pages/Home';
import { Dashboard } from './pages/Dashboard';
import { Docs } from './pages/Docs';
import { Playground } from './pages/Playground';
import { Auth } from './pages/Auth';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>(ViewState.LANDING);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [user, setUser] = useState<any>(null);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      // Redirect to dashboard if on Auth page and user logs in
      if (currentUser && view === ViewState.AUTH) {
        setView(ViewState.DASHBOARD);
      }
    });
    return () => unsubscribe();
  }, [view]);

  // Simple navigation handler
  const renderPage = () => {
    switch (view) {
      case ViewState.LANDING: return <Home onNavigate={setView} />;
      case ViewState.DASHBOARD: 
        if (!user) return <Auth onSuccess={() => setView(ViewState.DASHBOARD)} />;
        return <Dashboard />;
      case ViewState.DOCS: return <Docs />;
      case ViewState.PLAYGROUND: return <Playground />;
      case ViewState.AUTH: return <Auth onSuccess={() => setView(ViewState.DASHBOARD)} />;
      default: return <Home onNavigate={setView} />;
    }
  };

  const handleNavClick = (target: ViewState) => {
    // If attempting to go to dashboard but not logged in, show auth
    if (target === ViewState.DASHBOARD && !user) {
      setView(ViewState.AUTH);
    } else {
      setView(target);
    }
    setIsMobileMenuOpen(false);
  };

  const handleSignOut = async () => {
    await signOut(auth);
    setView(ViewState.LANDING);
  };

  const NavItem = ({ target, icon: Icon, label }: { target: ViewState; icon: any; label: string }) => (
    <button
      onClick={() => handleNavClick(target)}
      className={`flex items-center space-x-2 px-3 py-2 rounded-md text-sm font-medium transition-colors ${
        view === target 
          ? 'bg-brand-900/50 text-brand-400' 
          : 'text-slate-400 hover:text-white hover:bg-slate-800'
      }`}
    >
      <Icon className="w-4 h-4" />
      <span>{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-brand-500/30 selection:text-brand-200">

      {/* Navigation */}
      <nav className="sticky top-0 z-50 w-full border-b border-slate-800 bg-slate-950/80 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
