import { 
  collection, 
  addDoc, 
  getDocs, 
  query, 
  where, 
  doc, 
  deleteDoc, 
  updateDoc, 
  getDoc,
  serverTimestamp
} from 'firebase/firestore';
import { auth, db } from '../lib/firebase';
import { Project, DBEntry, Collection } from '../types';

// Helper to convert Firestore snapshots to our App types
const mapDocToProject = async (docSnap: any): Promise<Project> => {
  const data = docSnap.data();
  // We need to fetch collections manually since they are subcollections
  // Note: listing subcollections is not possible directly in client SDK without knowing names
  // For this architecture, we will store a metadata array of collection names on the parent project doc
  // OR we just query the known collections. 

  // Strategy: For the dashboard to be fast, we will store a 'collectionNames' array on the Project document.
  // When we fetch a project, we iterate those names to fetch the data.

  const colNames: string[] = data.collectionList || [];
  const collections: Collection[] = [];

  for (const name of colNames) {
    const colRef = collection(db, `projects/${docSnap.id}/collections/${name}/docs`);
    const snapshot = await getDocs(colRef);
    const entries = snapshot.docs.map(d => ({ id: d.id, ...d.data() }));
    collections.push({ name, entries });
  }

  return {
    id: docSnap.id,
    ownerId: data.ownerId,
    name: data.name,
    apiKey: data.apiKey,
    secretKey: data.secretKey,
    permissions: data.permissions,
    rules: data.rules || `{
  "users": {
    ".read": "true",
    ".write": "auth.uid == resource.id"
  }
}`,
    collections,
    createdAt: data.createdAt?.toDate?.()?.toISOString() || new Date().toISOString(),
    updatedAt: data.updatedAt?.toDate?.()?.toISOString() || new Date().toISOString(),
  };
};

export const FirebaseService = {
  // --- Management API ---

  createProject: async (name: string): Promise<Project> => {
    const user = auth.currentUser;
    if (!user) throw new Error("Must be logged in");

    const newProject = {
      ownerId: user.uid,
      name,
      apiKey: `pk_live_${Math.random().toString(36).substr(2, 16)}`,
      secretKey: `sk_live_${Math.random().toString(36).substr(2, 16)}`,
      permissions: {
        allowPublicRead: true,
        allowPublicWrite: false,
        allowedOrigins: ['perchance.org']
      },
      rules: `{
  "users": {
    ".read": "true",
    ".write": "auth.uid == resource.id"
  }
}`,
      collectionList: [], // Metadata to track subcollections
      createdAt: serverTimestamp(),
      updatedAt: serverTimestamp()
    };

    const docRef = await addDoc(collection(db, 'projects'), newProject);

    // Return formatted project
    return {
      id: docRef.id,
      ...newProject,
      collections: [],
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    } as Project;
  },

  getAllProjects: async (): Promise<Project[]> => {
    const user = auth.currentUser;
    if (!user) return [];

    const q = query(collection(db, 'projects'), where('ownerId', '==', user.uid));
    const querySnapshot = await getDocs(q);

    const projects = await Promise.all(querySnapshot.docs.map(mapDocToProject));
    return projects;
  },

  deleteProject: async (projectId: string): Promise<void> => {
    await deleteDoc(doc(db, 'projects', projectId));
  },

  updateProject: async (projectId: string, data: Partial<Project>): Promise<void> => {
    // We strip out the ID and complex types that shouldn't be saved directly if passed by accident
    const { id, collections, ...cleanData } = data as any;

    await updateDoc(doc(db, 'projects', projectId), {
      ...cleanData,
      updatedAt: serverTimestamp()
    });
  },

  // --- Runtime API (Used by Playground & eventually the Vercel API) ---

  runtimeAdd: async (apiKey: string, collectionName: string, data: any): Promise<any> => {
    // 1. Find Project by API Key (This requires a global query, strictly needs an index in Firestore)
    // Note: In a real high-scale app, we'd use the Project ID directly, but per user request we look up by key.
    const q = query(collection(db, 'projects'), where('apiKey', '==', apiKey));
    const querySnapshot = await getDocs(q);

    if (querySnapshot.empty) throw new Error("Invalid API Key");
    const projectDoc = querySnapshot.docs[0];
    const projectId = projectDoc.id;

    // 2. Ensure collection name is in the list
    const projectData = projectDoc.data();
    const currentList: string[] = projectData.collectionList || [];

    if (!currentList.includes(collectionName)) {
      await updateDoc(doc(db, 'projects', projectId), {
        collectionList: [...currentList, collectionName],
        updatedAt: serverTimestamp()
      });
    }

    // 3. Add Data
    const colRef = collection(db, `projects/${projectId}/collections/${collectionName}/docs`);
    const docRef = await addDoc(colRef, {
      ...data,
      _created: serverTimestamp()
    });

    return { id: docRef.id, ...data };
  },

  runtimeGet: async (apiKey: string, collectionName: string): Promise<DBEntry[]> => {
    const q = query(collection(db, 'projects'), where('apiKey', '==', apiKey));
    const querySnapshot = await getDocs(q);
    if (querySnapshot.empty) throw new Error("Invalid API Key");

    const projectId = querySnapshot.docs[0].id;
    const colRef = collection(db, `projects/${projectId}/collections/${collectionName}/docs`);
    const snapshot = await getDocs(colRef);

    return snapshot.docs.map(d => ({ id: d.id, ...d.data() }));
  },

  runtimeUpdate: async (apiKey: string, collectionName: string, docId: string, data: any): Promise<void> => {
    const q = query(collection(db, 'projects'), where('apiKey', '==', apiKey));
    const querySnapshot = await getDocs(q);
    if (querySnapshot.empty) throw new Error("Invalid API Key");

    const projectId = querySnapshot.docs[0].id;
    const docRef = doc(db, `projects/${projectId}/collections/${collectionName}/docs`, docId);

    await updateDoc(docRef, data);
  },

  runtimeDelete: async (apiKey: string, collectionName: string, docId: string): Promise<void> => {
    const q = query(collection(db, 'projects'), where('apiKey', '==', apiKey));
    const querySnapshot = await getDocs(q);
    if (querySnapshot.empty) throw new Error("Invalid API Key");

    const projectId = querySnapshot.docs[0].id;
    const docRef = doc(db, `projects/${projectId}/collections/${collectionName}/docs`, docId);

    await deleteDoc(docRef);
  }
};

import React, { useState, useEffect } from 'react';
import { Plus, Database, Key, Trash2, RefreshCw, Layers, Table as TableIcon, FileJson, Search, Pencil, Save, X, ChevronLeft, ChevronRight, Shield, Play, CheckCircle, XCircle } from 'lucide-react';
import { FirebaseService } from '../services/firebaseService';
import { Project, Collection, DBEntry } from '../types';
import { Button, Card, Input, Badge, Modal } from '../components/ui';

// --- Sub-components for Data Visualization ---

const ITEMS_PER_PAGE = 10;

interface CollectionTableProps {
  entries: DBEntry[];
  onEdit: (entry: DBEntry) => void;
  onDelete: (entry: DBEntry) => void;
}

const CollectionTable: React.FC<CollectionTableProps> = ({ 
  entries, 
  onEdit, 
  onDelete 
}) => {
  const [currentPage, setCurrentPage] = useState(1);

  useEffect(() => {
    setCurrentPage(1);
  }, [entries]);

  if (entries.length === 0) {
    return <div className="p-8 text-center text-slate-500 italic text-sm">No records in this collection. Add data to see it here.</div>;
  }

  const totalPages = Math.ceil(entries.length / ITEMS_PER_PAGE);
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
  const paginatedEntries = entries.slice(startIndex, startIndex + ITEMS_PER_PAGE);

  const allKeys = Array.from(new Set(entries.flatMap(entry => Object.keys(entry)))) as string[];

  const headers = [
    'id',
    ...allKeys.filter(k => k !== 'id' && k !== '_created').sort(),
    ...(allKeys.includes('_created') ? ['_created'] : [])
  ];

  return (
    <div className="flex flex-col h-full">
      <div className="overflow-x-auto custom-scrollbar pb-2 flex-1">
        <table className="min-w-full divide-y divide-slate-800/50 text-left border-collapse">
          <thead className="bg-slate-900 sticky top-0 z-10">
            <tr>
              {headers.map(header => (
                <th key={header} className="px-4 py-3 text-xs font-semibold text-slate-400 uppercase tracking-wider whitespace-nowrap border-b border-slate-700 select-none">
                  {header}
                </th>
              ))}
              <th className="px-4 py-3 text-xs font-semibold text-slate-400 uppercase tracking-wider whitespace-nowrap border-b border-slate-700 text-right sticky right-0 bg-slate-900 shadow-[-10px_0_10px_-5px_rgba(0,0,0,0.3)]">
                Actions
              </th>
            </tr>
          </thead>
          <tbody className="bg-slate-900/20 divide-y divide-slate-800/50">
            {paginatedEntries.map((entry) => (
              <tr key={entry.id} className="hover:bg-slate-800/50 transition-colors group">
                {headers.map(header => {
                  const value = entry[header];
                  let displayValue: React.ReactNode = value;
                  let isComplex = false;
                  let isEmpty = value === null || value === undefined;

                  if (isEmpty) {
                    displayValue = <span className="text-slate-700">-</span>;
                  } else if (typeof value === 'object') {
                    displayValue = JSON.stringify(value);
                    isComplex = true;
                  } else if (typeof value === 'boolean') {
                    displayValue = value ? (
                      <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-medium bg-emerald-500/10 text-emerald-400 border border-emerald-500/20">TRUE</span>
                    ) : (
                      <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-medium bg-red-500/10 text-red-400 border border-red-500/20">FALSE</span>
                    );
                  }

                  return (
                    <td key={`${entry.id}-${header}`} className="px-4 py-2 text-sm text-slate-300 whitespace-nowrap border-r border-slate-800/30 last:border-r-0 max-w-[250px]">
                      <div 
                        className={`truncate ${isComplex ? 'font-mono text-xs text-slate-500' : ''}`} 
                        title={typeof value === 'object' ? JSON.stringify(value, null, 2) : String(value)}
                      >
                        {displayValue}
                      </div>
                    </td>
                  );
                })}
                <td className="px-4 py-2 text-right sticky right-0 bg-slate-900/90 group-hover:bg-slate-800 backdrop-blur-sm border-l border-slate-800/50 shadow-[-10px_0_10px_-5px_rgba(0,0,0,0.3)]">
                   <div className="flex justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => onEdit(entry)} className="p-1 text-slate-400 hover:text-brand-400 hover:bg-brand-500/10 rounded transition-colors" title="Edit JSON">
                        <Pencil className="w-3.5 h-3.5" />
                      </button>
                      <button onClick={() => onDelete(entry)} className="p-1 text-slate-400 hover:text-red-400 hover:bg-red-500/10 rounded transition-colors" title="Delete">
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                   </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {totalPages > 1 && (
        <div className="flex items-center justify-between px-4 py-3 bg-slate-900/50 border-t border-slate-700/50">
          <div className="text-xs text-slate-400">
            Showing <span className="font-medium text-slate-200">{startIndex + 1}</span> to <span className="font-medium text-slate-200">{Math.min(startIndex + ITEMS_PER_PAGE, entries.length)}</span> of <span className="font-medium text-slate-200">{entries.length}</span> results
          </div>
          <div className="flex space-x-2">
            <Button 
              size="sm" 
              variant="outline" 
              onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
              disabled={currentPage === 1}
              className="px-2"
            >
              <ChevronLeft className="w-4 h-4" />
            </Button>
            <div className="flex items-center px-2 text-xs font-mono text-slate-400 bg-slate-800 rounded">
              Page {currentPage} / {totalPages}
            </div>
            <Button 
              size="sm" 
              variant="outline" 
              onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
              disabled={currentPage === totalPages}
              className="px-2"
            >
              <ChevronRight className="w-4 h-4" />
            </Button>
          </div>
        </div>
      )}
    </div>
  );
};

